  orderTooltipHeaderSecond?: number;
  iconColorOnOption?: typeAllowedIconColorOnOption;
  titleColorHideBg?: typeAllowedTitleColorHideBg;
  orderTooltipHeaderOption?: number;
  textTooltipHeaderOption?: string;
  descriptionTooltipHeaderOption?: string;
  nameTooltipHeaderOption?: string;
  currentStepTextTooltipHeaderOption?: string;
  lastStepTextTooltipHeaderOption?: string;
  textButtonTooltipHeaderOption?: string;
  activeTooltipOption?: boolean;
  hideBackground?: boolean;
  showNotification?: boolean;
  notificationsNumber?: string;
  firstRightSquareIconName?: PropsIconsNameCore;
  secondRightSquareIconName?: PropsIconsNameCore;

  orderTooltipHeaderFirstSquareIcon?: number;
  textTooltipHeaderFirstSquareIcon?: string;
  descriptionTooltipHeaderFirstSquareIcon?: string;
  nameTooltipHeaderFirstSquareIcon?: string;
  currentStepTextTooltipHeaderFirstSquareIcon?: string;
  lastStepTextTooltipHeaderFirstSquareIcon?: string;
